// Extract file information
const filePath = $input.item(0).json.file;
const fileName = filePath.split('/').pop();
const fileExt = fileName.split('.').pop().toLowerCase();
const fileNameWithoutExt = fileName.replace(`.${fileExt}`, '');

// Determine asset type from extension
const assetTypeMap = {
  'png': 'texture',
  'jpg': 'texture',
  'jpeg': 'texture',
  'fbx': '3d_model',
  'obj': '3d_model',
  'uasset': 'ue_asset',
  'blend': 'source_file'
};

const assetType = assetTypeMap[fileExt] || 'unknown';

// Get file stats
const fs = require('fs');
const stats = fs.statSync(filePath);
const fileSizeMB = (stats.size / (1024 * 1024)).toFixed(2);

// For images, we can analyze them with AI
// For 3D models, we'll analyze the filename and metadata
let analysisNeeded = ['texture', '3d_model'].includes(assetType);

return {
  filePath,
  fileName,
  fileNameWithoutExt,
  fileExt,
  assetType,
  fileSizeMB,
  analysisNeeded,
  createdAt: stats.birthtime.toISOString()
};

// Create AI prompt based on asset type
const metadata = $input.item(0).json;

let prompt = '';

if (metadata.assetType === 'texture') {
  prompt = `Analyze this game texture image and provide detailed categorization.

Filename: ${metadata.fileName}

Provide response in this JSON format:
{
  "category": "one of: albedo, normal, roughness, metallic, ambient_occlusion, height, emission, opacity",
  "materialType": "what material this represents (e.g., concrete, wood, metal, fabric, stone)",
  "quality": "low, medium, high, production",
  "tileable": true/false,
  "resolution": "estimated resolution like 1024x1024, 2048x2048, 4096x4096",
  "suggestedTags": ["array of relevant tags"],
  "suggestedFolder": "recommended folder structure like Materials/Environment/Stone",
  "pbr_ready": true/false,
  "description": "brief description of the texture"
}`;
} else if (metadata.assetType === '3d_model') {
  prompt = `Analyze this 3D model filename and categorize it for a game project.

Filename: ${metadata.fileNameWithoutExt}
Format: ${metadata.fileExt}
Size: ${metadata.fileSizeMB} MB

Provide response in this JSON format:
{
  "category": "one of: character, prop, environment, weapon, vehicle, architecture, vegetation",
  "subcategory": "more specific classification",
  "polyCount": "estimated: low_poly, mid_poly, high_poly, or hero based on file size",
  "suggestedTags": ["array of relevant tags"],
  "suggestedFolder": "recommended folder structure",
  "needsOptimization": true/false with reasoning,
  "description": "brief description"
}`;
}

return {
  metadata,
  prompt,
  hasImage: metadata.assetType === 'texture'
};

