// Parse AI response
const aiResponse = $input.item(0).json;
const metadata = $input.item(0).json.metadata;

const analysisText = aiResponse.choices[0].message.content;
const analysis = JSON.parse(analysisText);

// Combine metadata and AI analysis
const assetData = {
  ...metadata,
  ai_analysis: analysis,
  processing_date: new Date().toISOString(),
  destination_folder: `/home/user/UnrealProjects/MyGame/Content/${analysis.suggestedFolder}`
};

return assetData;

// Create metadata sidecar file
const assetData = $input.item(0).json;

const metadataContent = {
  asset_name: assetData.fileNameWithoutExt,
  file_type: assetData.fileExt,
  file_size_mb: assetData.fileSizeMB,
  imported_date: assetData.createdAt,
  processed_date: assetData.processing_date,
  ai_analysis: assetData.ai_analysis,
  tags: assetData.ai_analysis.suggestedTags,
  unreal_engine: {
    import_ready: true,
    suggested_settings: assetData.assetType === 'texture' ? {
      compression: assetData.ai_analysis.category === 'normal' ? 'Normalmap' : 'Default',
      srgb: assetData.ai_analysis.category === 'albedo',
      mip_gen_settings: 'FromTextureGroup'
    } : {}
  }
};

const metadataFilePath = `${assetData.destination_folder}/${assetData.fileNameWithoutExt}_metadata.json`;

return {
  assetData,
  metadataContent,
  metadataFilePath
};

